-- ---------------------------------------------------------------------
-- album_requests legacy renames (spectral_* split into last_download / current)
-- ---------------------------------------------------------------------

DO $$ BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'album_requests'
          AND column_name = 'spectral_bitrate'
    ) AND NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'album_requests'
          AND column_name = 'last_download_spectral_bitrate'
    ) THEN
        ALTER TABLE album_requests RENAME COLUMN spectral_bitrate TO last_download_spectral_bitrate;
    END IF;
END $$;

DO $$ BEGIN
    IF EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'album_requests'
          AND column_name = 'spectral_grade'
    ) AND NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'album_requests'
          AND column_name = 'last_download_spectral_grade'
    ) THEN
        ALTER TABLE album_requests RENAME COLUMN spectral_grade TO last_download_spectral_grade;
    END IF;
END $$;

DO $$ BEGIN
